import{_ as e,c as a,o as i,ag as t}from"./chunks/framework.BZemHgQ6.js";const k=JSON.parse('{"title":"Mounting a Disk Image to a Physical Server","description":"","frontmatter":{},"headers":[],"relativePath":"how_to/libvirt/mount-images.md","filePath":"how_to/libvirt/mount-images.md"}'),n={name:"how_to/libvirt/mount-images.md"};function o(l,s,p,d,h,c){return i(),a("div",null,s[0]||(s[0]=[t(`<h1 id="mounting-a-disk-image-to-a-physical-server" tabindex="-1">Mounting a Disk Image to a Physical Server <a class="header-anchor" href="#mounting-a-disk-image-to-a-physical-server" aria-label="Permalink to &quot;Mounting a Disk Image to a Physical Server&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Mounting a virtual disk image (e.g., QCOW2) to a physical Linux server allows you to access its contents as if it were a physical drive. This is useful for inspecting or modifying VM disk data without running the VM itself. In this guide, we’ll use <code>qemu-nbd</code> to mount a QCOW2 image on a Linux system with Qemu/KVM.</p><h2 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h2><ul><li><strong>Virtualization</strong>: Qemu/KVM.</li><li><strong>Operating System</strong>: Linux (e.g., Fedora, Ubuntu, CentOS, or Rocky Linux).</li><li><strong>Image Format</strong>: QCOW2 (or other formats supported by <code>qemu-nbd</code>).</li><li><strong>Tools</strong>: <code>qemu-nbd</code> (part of <code>qemu-utils</code> or <code>qemu-kvm</code> packages).</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="step-1-load-the-nbd-kernel-module" tabindex="-1">Step 1 - Load the NBD Kernel Module <a class="header-anchor" href="#step-1-load-the-nbd-kernel-module" aria-label="Permalink to &quot;Step 1 - Load the NBD Kernel Module&quot;">​</a></h3><p>The Network Block Device (NBD) kernel module allows you to map disk images to block devices (e.g., <code>/dev/nbd0</code>). Load it with support for up to 8 partitions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nbd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max_part=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span></span></code></pre></div><ul><li><code>max_part=8</code>: Enables recognition of up to 8 partitions within the image.</li><li>Run this once per boot; it persists until reboot.</li></ul><p>Ensure <code>qemu-nbd</code> is installed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-utils</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For Debian/Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # For RHEL/CentOS/Rocky</span></span></code></pre></div><h3 id="step-2-connect-the-qcow2-image-to-an-nbd-device" tabindex="-1">Step 2 - Connect the QCOW2 Image to an NBD Device <a class="header-anchor" href="#step-2-connect-the-qcow2-image-to-an-nbd-device" aria-label="Permalink to &quot;Step 2 - Connect the QCOW2 Image to an NBD Device&quot;">​</a></h3><p>Use <code>qemu-nbd</code> to connect the QCOW2 image to a block device (e.g., <code>/dev/nbd0</code>). Replace <code>/path/to/qcow2/image</code> with the actual path to your image:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-nbd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --connect=/dev/nbd0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/qcow2/image</span></span></code></pre></div><p><strong>Example</strong>: Connect an image located at <code>/home/bintang/os-centos-7-vol</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-nbd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --connect=/dev/nbd0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/bintang/os-centos-7-vol</span></span></code></pre></div><ul><li><code>--connect=/dev/nbd0</code>: Maps the image to <code>/dev/nbd0</code> (use <code>nbd1</code>, <code>nbd2</code>, etc., if <code>nbd0</code> is in use).</li><li>The image must be a valid QCOW2 file.</li></ul><h3 id="step-3-verify-the-connected-disk" tabindex="-1">Step 3 - Verify the Connected Disk <a class="header-anchor" href="#step-3-verify-the-connected-disk" aria-label="Permalink to &quot;Step 3 - Verify the Connected Disk&quot;">​</a></h3><p>Check the disk information to confirm the image is mapped and inspect its partitions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fdisk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Disk /dev/nbd0: 30 GiB, 32212254720 bytes, 62914560 sectors</span></span>
<span class="line"><span>Units: sectors of 1 * 512 = 512 bytes</span></span>
<span class="line"><span>Sector size (logical/physical): 512 bytes / 512 bytes</span></span>
<span class="line"><span>I/O size (minimum/optimal): 512 bytes / 512 bytes</span></span>
<span class="line"><span>Disklabel type: dos</span></span>
<span class="line"><span>Disk identifier: 0x000940fd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Device      Boot Start      End  Sectors Size Id Type</span></span>
<span class="line"><span>/dev/nbd0p1 *     2048 62914526 62912479  30G 83 Linux</span></span></code></pre></div><ul><li><code>/dev/nbd0p1</code>: Indicates the first partition of the image.</li><li>If no partitions appear, the image may lack a partition table (e.g., it’s a raw filesystem).</li></ul><h3 id="step-4-mount-the-disk-image" tabindex="-1">Step 4 - Mount the Disk Image <a class="header-anchor" href="#step-4-mount-the-disk-image" aria-label="Permalink to &quot;Step 4 - Mount the Disk Image&quot;">​</a></h3><p>Mount the partition to a directory (e.g., <code>/mnt</code>). Replace <code>/mnt</code> with your desired mount point if needed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd0p1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span></code></pre></div><p><strong>Example</strong>: Mount to <code>/mnt/tes</code> (create it first if it doesn’t exist with <code>sudo mkdir -p /mnt/tes</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd0p1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/tes</span></span></code></pre></div><p>Verify the mount:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -kh</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Filesystem      Size  Used Avail Use% Mounted on</span></span>
<span class="line"><span>devtmpfs        4.0M     0  4.0M   0% /dev</span></span>
<span class="line"><span>tmpfs           985M     0  985M   0% /dev/shm</span></span>
<span class="line"><span>tmpfs           394M  1.4M  393M   1% /run</span></span>
<span class="line"><span>/dev/sda2        29G   22G  7.0G  76% /</span></span>
<span class="line"><span>tmpfs           985M   16K  985M   1% /tmp</span></span>
<span class="line"><span>/dev/sda2        29G   22G  7.0G  76% /home</span></span>
<span class="line"><span>/dev/sda1       974M  220M  687M  25% /boot</span></span>
<span class="line"><span>tmpfs           197M  108K  197M   1% /run/user/1000</span></span>
<span class="line"><span>/dev/nbd0p1      30G  837M   30G   3% /mnt/tes</span></span></code></pre></div><ul><li><code>/dev/nbd0p1</code> is now mounted at <code>/mnt/tes</code>, and you can access its files there.</li></ul><h4 id="disconnect-the-image" tabindex="-1">Disconnect the Image <a class="header-anchor" href="#disconnect-the-image" aria-label="Permalink to &quot;Disconnect the Image&quot;">​</a></h4><p>When finished, unmount and disconnect the image:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-nbd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --disconnect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd0</span></span></code></pre></div><ul><li><code>umount</code>: Removes the mount point.</li><li><code>--disconnect</code>: Frees the NBD device.</li></ul><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><ul><li>If the image has multiple partitions (e.g., <code>/dev/nbd0p2</code>), mount them separately.</li><li>For encrypted QCOW2 images (e.g., LUKS), additional steps are required (see a LUKS-specific guide).</li><li>Ensure the mount point exists before mounting (<code>sudo mkdir /mnt</code> if needed).</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://www.xmodulo.com/mount-qcow2-disk-image-linux.html" target="_blank" rel="noreferrer">Xmodulo: How to Mount a QCOW2 Disk Image on Linux</a></li></ul>`,42)]))}const u=e(n,[["render",o]]);export{k as __pageData,u as default};
